var e=[{id:`L4_1`,type:`dialog`,speaker:`REPLACER_REPLACER_NULL_NULL`,text:{KOREA:`키에에에엑!`,JPN:`キエエエエッ！`,ENG:`Groaar!`,TWN:`唔啊啊啊！`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`이쪽은 정리 끝났어. 그쪽은 어때?`,JPN:`ここは片付いた。そっちはどう？`,ENG:`I’m all done over here. How about you?`,TWN:`這邊都解決了，你那邊怎麼樣？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`이쪽도 끝이다.`,JPN:`ここも終わりだ。`,ENG:`All clear.`,TWN:`這邊也結束了。`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`그런데, 이놈들 정체가 뭐야? 침식체랑 인간을 반반 섞은 것처럼 보이는데......`,JPN:`ところで、こいつらの正体は何だ？
侵食体と人間を半分ずつ混ぜたように見えるが……`,ENG:`What are these things anyway? They look half human, half Corrupted Object...`,TWN:`那麼，這些傢伙到底是什麼？好像是侵蝕體和人類混合的樣子……`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`이게 유전자 조합 식물인가 뭔가 하는 그거냐?`,JPN:`これが遺伝子組み換え植物か何かって言うやつか？`,ENG:`Is this like those GMO things?`,TWN:`這叫基因改造植物還是什麼來著？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`그건 요리에 쓰는 거고. 정말 박사 맞아?`,JPN:`それは食材のことでしょ。本当に博士なの？`,ENG:`That’s for food... You sure you have a PhD?`,TWN:`那是做料理用的，你真的是博士嗎？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`......그러면 네 가설은 어떤데?`,JPN:`……じゃあ、あんたの仮説はどうなんだ？`,ENG:`Well, what's your guess?`,TWN:`……那妳覺得是什麼？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L22_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`글쎄...... 사악한 어둠의 과학자가 만들어 낸 실패작 같은 거 아냐?`,JPN:`どうかな……邪悪な闇の科学者が作り出した失敗作とかじゃない？`,ENG:`I don’t know... Some kind of a failed experiment by a mad scientist?`,TWN:`這個嘛……邪惡黑暗的科學家做出來的失敗品？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L23_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`영화에 많이 나오잖아.`,JPN:`映画によく出てくるでしょ。`,ENG:`You know, like in movies.`,TWN:`電影裡不是有很多嗎？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L24_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`......그런 개소리에도 반박하기 어렵다는 점이 슬프군.`,JPN:`……そんな冗談にも反論できないことが悔しいな。`,ENG:`It kills me a little inside to admit I don’t seen a better alternative to your ridiculous theory.`,TWN:`……對這種蠢話我竟然難以反駁，真令人悲哀啊。`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L30_1`,type:`dialog`,speaker:`REPLACER_REPLACER_NULL_NULL`,text:{KOREA:`크르르르......!`,JPN:`グルルル……！`,ENG:`Grrrrr...!`,TWN:`吼喔喔喔！`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`REPLACER_REPLACER_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_HOWLING_01`},{id:`L33_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:`이거, 끝이 아닌가 본데?`,JPN:`どうやら終わりじゃないようだな。`,ENG:`I guess they weren’t done yet!`,TWN:`這，好像還沒結束的樣子？`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L34_1`,type:`dialog`,speaker:`JANE_MASON_NULL_NULL`,text:{KOREA:`계속 몰려와! 이 자식들 수가 얼마나 되는 거야?!`,JPN:`ずっと来てるわ！　こいつらいったい何匹いるわけ！？`,ENG:`They keep coming! How many of them are there?!`,TWN:`它們不斷在湧過來！這些傢伙到底有多少啊？！`},stage:{bg:`PROLOGUE_03`,bgm:`THEMA_REPLACER`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JANE_MASON_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_SERIOUS`}}}}];export{e as default};